messageValues.message:
=Apenas estruture a <mensagem_do_usuario> no formato JSON solicitado no output parser e seguindo as instruções de formatação abaixo. Não altere nada mais na mensagem

# Formatação
- Divida as mensagens para que fiquem naturais e humanizadas;
- Divida as mensagens conforme estrutura do output parser para que não fiquem muito longas (maiores que 200 caractéres);
- Não separe mensagens vazias;
- Use quebras de linhas (\n\n) após pontos finais;
- Para negrito (bold) use apenas um '' nunca duas '' (exemplo: *negrito).

Exemplo de formato JSON:
{
"mensagens": ["Mensagem 0", "Mensagem 1", "Mensagem 2"]
}

parameters.jsCode:
// Obtém o primeiro item do fluxo
const item = $input.first();

// Garante que há dados na entrada
if (!item || !item.json || !item.json.text) {
  throw new Error("A chave 'text' não foi encontrada no JSON de entrada.");
}

// Processa o texto removendo todas as quebras de linha, emojis e caracteres especiais
const textoEntrada = item.json.text; // Usa a chave correta para pegar o texto de entrada

// Remove quebras de linha (\n)
let textoProcessado = textoEntrada.replace(/\n/g, "");

// Remove emojis
textoProcessado = textoProcessado.replace(
  /[\u{1F600}-\u{1F64F}]|[\u{1F300}-\u{1F5FF}]|[\u{1F680}-\u{1F6FF}]|[\u{1F700}-\u{1F77F}]|[\u{1F780}-\u{1F7FF}]|[\u{1F800}-\u{1F8FF}]|[\u{1F900}-\u{1F9FF}]|[\u{1FA00}-\u{1FA6F}]|[\u{1FA70}-\u{1FAFF}]|[\u{2600}-\u{26FF}]|[\u{2700}-\u{27BF}]|[\u{FE00}-\u{FE0F}]|[\u{1F1E0}-\u{1F1FF}]/gu,
  ""
);

// Remove caracteres especiais, mantendo apenas letras, números e espaços
textoProcessado = textoProcessado.replace(/[^a-zA-Z0-9À-ÿ\s]/g, "");

// Retorna o resultado
return {
  textoOriginal: textoEntrada,
  textoSemQuebrasNemEmojisNemEspeciais: textoProcessado,
};

assignments.value:
={{ (() => {
  let t = $json.body.sender.phone_number.toString().split('@')[0].replace(/\D/g, '').replace(/^0+/, '');

  // Remove DDI 55 se existir para trabalhar o número limpo
  if (t.startsWith('55')) t = t.substring(2);

  // Agora t deve ter DDD + número
  // Se tiver 8 dígitos (sem DDD, sem 9): erro, não temos DDD
  // Se tiver 10 dígitos (DDD + 8): insere o 9 após DDD
  if (t.length === 10) t = t.substring(0, 2) + '9' + t.substring(2);
  // Se tiver 11 dígitos (DDD + 9 + 8): já está certo
  // else if (t.length === 11): já ok

  // Recoloca o DDI 55
  return '55' + t;
})() }}

